import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import { HeatmapChart } from './charts.js';
import { Title, Tooltip, VisualMap } from './components.js';

const meta = {
  component: HeatmapChart,
} satisfies Meta<typeof HeatmapChart>;

export default meta;
type Story = StoryObj<typeof meta>;

const generateData = () => {
  const data = [];
  for (let x = 0; x < 7; x++) {
    for (let y = 0; y < 24; y++) {
      data.push([x, y, Math.floor(Math.random() * 100)]);
    }
  }
  return data;
};

export const Default: Story = {
  render: () => (
    <HeatmapChart
      style={{ width: '100%', height: '100%' }}
      xAxis={{
        type: 'category',
        data: Array.from({ length: 24 }, (_, i) => `${i}:00`),
      }}
      yAxis={{
        type: 'category',
        data: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
      }}
      series={[
        {
          data: generateData(),
          type: 'heatmap',
          label: { show: false },
        },
      ]}
    >
      <VisualMap min={0} max={100} />
    </HeatmapChart>
  ),
  play: async ({ canvas }) => {
    const chartContainer = canvas.querySelector('[style*="width"]');
