for file in src/*.stories.tsx; do
  if [ "$file" != "src/BarChart.stories.tsx" ]; then
    node -e "
      const fs = require('fs');
      const content = fs.readFileSync('$file', 'utf8');
      const fixed = content.replace(/^export const ([A-Z][a-zA-Z]*): Story = \{$/gm, 'export const \$1: Story = {\n  args: {} as never,');
      fs.writeFileSync('$file', fixed);
    "
  fi
done

